{
  "semantic_mode": "stable",
  "lean": "theorem is_stable_sorting_specification : Sorter → Prop := λ sorter, ∀ (l : List α), is_sorted (sorter l) ∧ is_permutation l (sorter l)",
  "assumptions": [
    "Sorter is a function that takes a list and returns a sorted list"
  ],
  "preconditions": [
    "Input list l is finite"
  ],
  "postconditions": [
    "The output list is sorted",
    "The output list is a permutation of the input list"
  ],
  "invariants": [
    "Order of equal elements is preserved",
    "Duplicates in the input list are preserved"
  ],
  "examples": [
    "[3, 1, 2] → [1, 2, 3]",
    "[5, 2, 5, 1] → [1, 2, 5, 5]"
  ],
  "notes": [
    "Stable sorting maintains the relative order of equal elements",
    "Permutation preserving ensures no elements are lost or added"
  ]
}

{
  "semantic_mode": "stable",
  "lean": "def is_sorted {α : Type} [preorder α] : list α → Prop := sorted (≤)",
  "assumptions": [
    "α is a type",
    "[preorder α] is a preorder on α"
  ],
  "preconditions": [
    "input list is of type α"
  ],
  "postconditions": [
    "output list is a permutation of the input list",
    "output list is sorted in non-decreasing order"
  ],
  "invariants": [
    "sortedness property is maintained throughout the sorting process"
  ],
  "examples": [
    "[3, 1, 4, 1, 5, 9, 2, 6, 5, 3, 5] -> [1, 1, 2, 3, 3, 4, 5, 5, 5, 6, 9]"
  ],
  "notes": [
    "This specification guarantees that the sorting algorithm preserves the relative order of equal elements",
    "The output list contains all elements of the input list without any additions or removals"
  ]
}

{
  "semantic_mode": "stable",
  "lean": "theorem sorting_spec_stable_permutation_preserving : ∀ (s : List α), is_sorted s → is_stable_sorting_spec s",
  "assumptions": [
    "α : Type*",
    "is_sorted : List α → Prop",
    "is_stable_sorting_spec : List α → Prop"
  ],
  "preconditions": [
    "s is a list of elements of type α"
  ],
  "postconditions": [
    "The sorting specification is stable and permutation preserving"
  ],
  "invariants": [
    "The relative order of equal elements is preserved"
  ],
  "examples": [
    "[3, 1, 2, 1] -> [1, 1, 2, 3]",
    "[5, 4, 3, 2, 1] -> [1, 2, 3, 4, 5]"
  ],
  "notes": [
    "Stable sorting ensures that equal elements maintain their relative order",
    "Permutation preserving guarantees that the output is a permutation of the input"
  ]
}

