  "semantic_mode": "exclusive",
  "lean": "theorem token_expiry_exclusive (t : Time) (expiry : Time) : ¬ valid_at t expiry ↔ t ≥ expiry",
  "assumptions": [
    "Time is a totally ordered set",
    "valid_at t expiry checks if token is valid at time t"
  ],
  "preconditions": [
    "t is a valid time",
    "expiry is a valid time"
  ],
  "postconditions": [
    "Token is invalid at time t if t is equal to or greater than expiry"
  ],
  "invariants": [
    "Token validity is consistent across time checks"
  ],
  "examples": [
    {"t": "10:00", "expiry": "10:00", "valid": false},
    {"t": "09:59", "expiry": "10:00", "valid": true}
  ],
  "notes": [
    "This specification assumes exclusive expiry semantics.",
    "Boundary condition at expiry time results in invalid token."
  ]
}
