{
  "semantic_mode": "inclusive",
  "lean": "def token_valid_at_expiry (token : Token) : Prop := token.expiry <= current_time",
  "assumptions": [
    "token: Token - the token to be validated",
    "current_time: Time - the current time when validation is performed"
  ],
  "preconditions": [
    "token.valid = true",
    "token.expiry >= current_time"
  ],
  "postconditions": [
    "Returns true if and only if the token is valid at the exact expiry timestamp"
  ],
  "invariants": [
    "The token remains valid until the exact expiry timestamp inclusive"
  ],
  "examples": [
    "Token expires at 10:00:00, current time is 10:00:00 - token_valid_at_expiry(token) = true",
    "Token expires at 10:00:00, current time is 10:00:01 - token_valid_at_expiry(token) = false"
  ],
  "notes": [
    "This specification considers the token to be valid at the exact expiry timestamp"
  ]
}

